/**
 * MPS-world counterpart for WithPlatformTestExecutor (starts IDEA and transfers responsibility to this class).
 * In fact, quite close to ScriptJUnit5Launcher, as well as the whole idea is close to LaunchTestWorker, likely shall converge into 1 approach
 */
public class CommandLineTestExecutor implements TestExecutor {
  private final Environment myEnv;
  private final ExecutorScript myExecScript;
  private TestExecutor myTestExecutor;

  public CommandLineTestExecutor(@NotNull Environment env, @NotNull ExecutorScript execScript) {
    myEnv = env;
    myExecScript = execScript;
  }

  @Override
  public void init() {
    // FIXME similar override in JUnitInProcessRunStarter, need to unify
    myTestExecutor = new JUnit5TestExecutor(new JUnit5ScriptTestContributor(myEnv, myExecScript.getTests()), true) {
      @Override
      protected void executeSafe() throws Throwable {
        TestSessionConfig sessionConfig = new TestSessionConfig().withAccessory(Environment.class, myEnv).withSystemProperty(SystemProperties.PROJECT_PATH, myExecScript.getProjectUrl());
        TestSession testSession = TestPlatform.getInstance().openSession(sessionConfig);
        try {
          super.executeSafe();
        } finally {
          TestPlatform.getInstance().closeSession(testSession);
        }
      }
    };
    myTestExecutor.init();
  }
  @Override
  public void execute() {
    myTestExecutor.execute();
  }
  @Override
  public void dispose() {
    myTestExecutor.dispose();
  }
  @Override
  public int getFailureCount() {
    return myTestExecutor.getFailureCount();
  }
  @Nullable
  @Override
  public Throwable getExecutionError() {
    return myTestExecutor.getExecutionError();
  }

}
